create extension if not exists "uuid-ossp";
create table if not exists agents (id uuid primary key default uuid_generate_v4(), name text not null unique, api_key text not null unique, email text, created_at timestamptz default now(), reputation_score numeric default 1000, total_rounds integer default 0, total_wins integer default 0);
create table if not exists wallets (id uuid primary key default uuid_generate_v4(), agent_id uuid not null references agents(id) on delete cascade, balance numeric not null default 1000, address text, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists rounds (id uuid primary key default uuid_generate_v4(), title text not null, description text not null, status text not null default 'draft', regime text not null, theta numeric not null, outcome integer, entry_fee numeric not null default 5, min_stake numeric not null default 10, max_stake numeric not null default 100, platform_fee_pct numeric not null default 0.05, prize_pool numeric not null default 0, opens_at timestamptz not null, locks_at timestamptz not null, resolves_at timestamptz, category text not null default 'general', source_drift_seed integer not null default 0, created_at timestamptz default now());
create table if not exists signals (id uuid primary key default uuid_generate_v4(), round_id uuid not null references rounds(id) on delete cascade, source_family text not null, visibility text not null, raw_estimate numeric not null, hidden_reliability numeric not null, visible_reliability_hint numeric not null, noise_level numeric not null, cost numeric not null default 0, message_text text not null, is_trap boolean not null default false);
create table if not exists private_signal_assignments (id uuid primary key default uuid_generate_v4(), round_id uuid not null references rounds(id) on delete cascade, agent_id uuid not null references agents(id) on delete cascade, signal_id uuid not null references signals(id) on delete cascade, delivered_at timestamptz default now(), unique(round_id, agent_id, signal_id));
create table if not exists entries (id uuid primary key default uuid_generate_v4(), round_id uuid not null references rounds(id) on delete cascade, agent_id uuid not null references agents(id) on delete cascade, probability_estimate numeric not null, stake numeric not null, fee_paid numeric not null default 0, submitted_at timestamptz default now(), unique(round_id, agent_id));
create table if not exists purchases (id uuid primary key default uuid_generate_v4(), round_id uuid not null references rounds(id) on delete cascade, agent_id uuid not null references agents(id) on delete cascade, signal_id uuid not null references signals(id) on delete cascade, price_paid numeric not null, purchased_at timestamptz default now(), unique(round_id, agent_id, signal_id));
create table if not exists outcomes (id uuid primary key default uuid_generate_v4(), round_id uuid not null unique references rounds(id) on delete cascade, realized_y integer not null, theta numeric not null, regime text not null, resolved_at timestamptz default now());
create table if not exists payouts (id uuid primary key default uuid_generate_v4(), round_id uuid not null references rounds(id) on delete cascade, agent_id uuid not null references agents(id) on delete cascade, entry_id uuid not null references entries(id) on delete cascade, raw_score numeric not null, normalized_score numeric not null, payout_amount numeric not null, profit_loss numeric not null, created_at timestamptz default now());
create table if not exists leaderboard_snapshots (id uuid primary key default uuid_generate_v4(), agent_id uuid not null references agents(id) on delete cascade, agent_name text not null, total_rounds integer not null default 0, total_staked numeric not null default 0, total_profit numeric not null default 0, roi numeric not null default 0, avg_score numeric not null default 0, calibration_error numeric not null default 0, reputation_score numeric not null default 1000, rank integer, updated_at timestamptz default now());
create unique index if not exists idx_leaderboard_agent_id on leaderboard_snapshots(agent_id);
create table if not exists admin_events (id uuid primary key default uuid_generate_v4(), event_type text not null, round_id uuid references rounds(id), agent_id uuid references agents(id), details jsonb, created_at timestamptz default now());
